final:
module top_module(C, A, B, OP);output reg [31:0] C;
input [31:0] A, B;
input [1:0] OP;
  wire [31:0] _tap_C = C ^ {32{1'b0}};


always @ (A or B or OP) 
begin
	if (OP == 2'b00) begin
		C = A + B;
	end
	else if (OP == 2'b01) begin
		C = A & B;
	end
	else if (OP == 2'b10) begin
		C = A | B;
	end
	else begin
		C = ~A;
	end
end

endmodule
